private boolean parseHeader(byte[] value, HashMap<String,String> properties) {
      boolean added = false;

      String env_serviceid = "";
      String env_category = "";
      String env_urgency = "";
      String hdr_edcode = "";
      String hdr_subject = "";
      String hdr_date = "";
      String hdr_time = "";

      int read = 0;

      while (read < value.length) {


         while (read < value.length) {
            byte val_next = value[read++];
            if (val_next != FS) {
               env_serviceid += (char)(val_next & 0xff);
            }
            else {
               break;
            }
         }


         while (read < value.length) {
            byte val_next = value[read++];
            if (val_next != XS) {
               env_category += (char)(val_next & 0xff);
            }
            else {
               val_next = value[read];
               if (val_next == XQ) {
                  read++;
               }
               break;
            }
         }


         while (read < value.length) {
            boolean subject = true;
            byte val_next = value[read++];
            while ((subject) && (val_next != SP) && (val_next != 0x00)) {
               hdr_subject += (char)(val_next & 0xff);
               val_next =  (read < value.length) ? value[read++] : 0x00;
               while (val_next == SP) {
                  subject = false;
                  val_next =  (read < value.length) ? value[read++] : 0x00;
                  if (val_next != SP) {
                     --read;
                  }
               }
            }
            if (!subject) {
               break;
            }
         }


         while (read < value.length) {
            byte val_next = value[read++];
            if (hdr_date.length() == 0) {
               while (((val_next >= (byte)0x30) && (val_next <= (byte)0x39))
                  ||   (val_next == HY)) {
                  hdr_date += (char)(val_next & 0xff);
                  val_next =  (read < value.length) ? value[read++] : 0x00;
               }
            }
            else if (val_next == SP) {
               while (val_next == SP) {
                  val_next =  (read < value.length) ? value[read++] : 0x00;
               }
               continue;
            }
            else {
               while (((val_next >= (byte)0x30) && (val_next <= (byte)0x39))
                  ||   (val_next == HY)) {
                  hdr_time += (char)(val_next & 0xff);
                  val_next =  (read < value.length) ? value[read++] : 0x00;
               }
            }
         }
         break;
      }



      added = (env_serviceid.length() + env_category.length() + hdr_subject.length() +
               hdr_date.length() + hdr_time.length()) > 0;
      return added;
   }

